+import { $internal } from '../common';
+import { isRelation, isRelationPair } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord } from '../trait/types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: AspectSchema<T>;
+};
+
+export type AspectSchema<T extends readonly Trait[]> = {
+    [K in keyof UnionToIntersection<T[number] extends Trait<infer S> ? S : never>]: UnionToIntersection<
+        T[number] extends Trait<infer S> ? S : never
+    >[K];
+};
+
+export type AspectRecord<T extends Aspect> = UnionToIntersection<
+    T['traits'][number] extends infer C ? (C extends Trait ? TraitRecord<C> : never) : never
+>;
+
+type UnionToIntersection<T> = (T extends any ? (value: T) => void : never) extends (
+    value: infer Result
+) => void
+    ? Result
+    : never;
+
+let aspectId = 0;
+
+export function createAspect<T extends readonly [Trait | Aspect, Trait | Aspect, ...(Trait | Aspect)[]]>(
+    ...constituents: T
+): Aspect<FlattenAspects<T>> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+
+    for (const constituent of constituents) {
+        if (isRelation(constituent) || isRelationPair(constituent)) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+
+        const flattened = isAspect(constituent) ? constituent.traits : [constituent];
+        for (const trait of flattened) {
+            if (trait[$internal].relation) {
+                throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            }
+
+            for (const field of Object.keys(trait.schema as Schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Koota: Aspect constituents cannot share the field "${field}".`);
+                }
+                fields.add(field);
+            }
+            traits.push(trait);
+        }
+    }
+
+    const schema = Object.assign({}, ...traits.map((trait) => trait.schema));
+    return Object.freeze({ [$aspect]: true, id: aspectId++, traits: Object.freeze(traits), schema }) as Aspect<
+        FlattenAspects<T>
+    >;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+type FlattenOne<T> = T extends Aspect<infer Traits> ? Traits[number] : T extends Trait ? T : never;
+export type FlattenAspects<T extends readonly unknown[]> = { [K in keyof T]: FlattenOne<T[K]> };
