+function createAspectQueryResult(world: World, entities: Entity[], params: QueryParameter[]) {
+    const results = Object.assign(entities, {
+        readEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) callback(readAspectState(world, entities[i], params), entities[i], i);
+            return results;
+        },
+        updateEach(callback: (state: any[], entity: Entity, index: number) => void, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readAspectState(world, entity, params);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                let stateIndex = 0;
+                for (const param of params) {
+                    if (isAspect(param)) {
+                        setTrait(world, entity, param as any, state[stateIndex++], options.changeDetection !== 'never');
+                    } else if (!isModifier(param) && !isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') {
+                        setTrait(world, entity, param as Trait, state[stateIndex++], options.changeDetection !== 'never');
+                    }
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) { callback([], entities); return results; },
+        select<U extends QueryParameter[]>(...next: U) { return createAspectQueryResult(world, entities, next) as QueryResult<U>; },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) { Array.prototype.sort.call(entities, callback); return results; },
